import{_ as o,c as t,o as i,ag as n}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"DAG Designer Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-designer/SPEC.md","filePath":"packages/dag-designer/SPEC.md"}'),a={name:"packages/dag-designer/SPEC.md"};function r(c,e,d,s,l,p){return i(),t("div",null,e[0]||(e[0]=[n('<h1 id="dag-designer-specification" tabindex="-1">DAG Designer Specification <a class="header-anchor" href="#dag-designer-specification" aria-label="Permalink to &quot;DAG Designer Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Composable React DAG designer UI package. Provides components, hooks, and an API client for authoring DAG definitions, managing node catalogs, and executing runs with real-time progress streaming. Run execution is server-authoritative via API; the designer does not perform local orchestration.</p><p>Run client contract: <code>createRun -&gt; startRun -&gt; getRunResult</code> with <code>traces/totalCostUsd</code> in results.</p><p><code>text-template</code> node template syntax:</p><ul><li><code>%s</code>: replace with input text</li><li><code>%%s</code>: render literal <code>%s</code></li><li>default template is <code>%s</code> (pass-through behavior)</li></ul><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Depends on <code>dag-core</code> for domain types (<code>IDagDefinition</code>, <code>IDagNode</code>, <code>INodeManifest</code>, <code>TPortPayload</code>, <code>TRunProgressEvent</code>, etc.).</li><li>Does NOT import <code>dag-runtime</code>, <code>dag-worker</code>, or <code>dag-scheduler</code> implementations directly.</li><li>Does not own backend storage or execution infrastructure.</li><li>Does not own API contract definitions for the server side -- those belong to <code>dag-api</code>.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><ul><li><strong>Contracts</strong> (<code>contracts/designer-api.ts</code>): Defines the <code>IDesignerApiClient</code> interface and all request/response types for the designer-to-server communication.</li><li><strong>API Client</strong> (<code>client/designer-api-client.ts</code>): <code>DesignerApiClient</code> implements <code>IDesignerApiClient</code> using <code>fetch</code> for REST calls and <code>EventSource</code> for SSE-based run progress streaming with exponential backoff reconnection.</li><li><strong>React Hooks</strong>: <ul><li><code>useDagDesignerState()</code> -- accesses designer state (definition, manifests, selection, run result, run progress, errors).</li><li><code>useDagDesignerActions()</code> -- accesses designer mutation actions (updateDefinition, addNode, updateNode, updateEdge, setSelection, etc.).</li><li><code>useDagDesignApi(options)</code> -- provides a typed API facade wrapping <code>IDesignerApiClient</code> for React components.</li></ul></li><li><strong>React Components</strong> (<code>components/</code>): <ul><li><code>DagDesignerCanvas</code> -- main canvas with context provider</li><li><code>DagNodeView</code> -- node rendering</li><li><code>DagBindingEdge</code> -- edge rendering with binding visualization</li><li><code>NodeExplorerPanel</code> -- node catalog browser</li><li><code>NodeConfigPanel</code> -- node configuration editor</li><li><code>EdgeInspectorPanel</code> -- edge/binding inspector</li><li><code>NodeIoViewer</code> -- input/output data viewer</li><li><code>NodeIoTracePanel</code> -- execution trace viewer</li></ul></li><li><strong>Lifecycle</strong> (<code>lifecycle/run-engine.ts</code>): Re-exports <code>IRunNodeTrace</code> and <code>IRunResult</code> types.</li><li><strong>Utilities</strong>: <code>schema-defaults.ts</code> (config schema default generation), <code>port-editor-utils.ts</code> (port editing helpers).</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IDesignerApiClient</code> -- client interface for all designer-to-server API operations</li><li><code>IDesignerApiClientConfig</code> -- client configuration (baseUrl)</li><li><code>ICreateDefinitionInput</code>, <code>IUpdateDraftInput</code>, <code>IValidateDefinitionInput</code>, <code>IPublishDefinitionInput</code>, <code>IGetDefinitionInput</code>, <code>IListDefinitionsInput</code> -- client-side input types</li><li><code>IDesignerCreateRunInput</code>, <code>IDesignerStartRunInput</code>, <code>IGetRunResultInput</code> -- run operation inputs (designer-prefixed to avoid collision with dag-runtime)</li></ul><p>Imported from other packages (not owned here):</p><ul><li><code>IProblemDetails</code>, <code>IDefinitionListItem</code> -- imported from <code>@robota-sdk/dag-api</code></li><li><code>IRunNodeTrace</code>, <code>IRunResult</code> -- imported from <code>@robota-sdk/dag-server-core</code></li><li><code>IDagDesignerState</code>, <code>IDagDesignerActions</code> -- React state/action interfaces</li><li><code>IUseDagDesignApi</code>, <code>IUseDagDesignApiOptions</code> -- hook interfaces</li><li><code>IRunProgressState</code> -- run progress tracking state (from canvas component)</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><ul><li><code>DesignerApiClient</code> -- HTTP/SSE client implementing <code>IDesignerApiClient</code></li><li><code>useDagDesignerState()</code> -- React hook for read-only designer state</li><li><code>useDagDesignerActions()</code> -- React hook for designer mutations</li><li><code>useDagDesignApi(options)</code> -- React hook wrapping API client</li><li><code>DagDesignerCanvas</code> -- main canvas React component</li><li><code>DagNodeView</code>, <code>DagBindingEdge</code> -- graph element components</li><li><code>NodeExplorerPanel</code>, <code>NodeConfigPanel</code>, <code>EdgeInspectorPanel</code> -- panel components</li><li><code>NodeIoViewer</code>, <code>NodeIoTracePanel</code> -- data/trace viewer components</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>IDesignerApiClient</code> -- implement to provide a custom API client (e.g., mock client for testing, alternative transport).</li><li><code>useDagDesignApi({ client })</code> -- accepts a custom client instance, enabling dependency injection in React.</li><li>Canvas component accepts <code>onRunResult</code> callback for custom run result handling.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>Client-side errors use <code>IProblemDetails</code> (mirroring the server shape):</p><ul><li><code>DESIGNER_API_CONTRACT_VIOLATION</code> -- response payload does not match the expected designer API contract (type: <code>urn:robota:problems:dag:contract</code>)</li><li>Server-originated <code>IProblemDetails</code> errors are passed through from the API response.</li><li><code>EventSource</code> errors surface via <code>onError</code> callback: <code>&quot;EventSource is not available&quot;</code>, <code>&quot;Run progress stream disconnected&quot;</code>, <code>&quot;Failed to parse run progress event payload&quot;</code>.</li></ul><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IDesignerApiClient</code></td><td><code>DesignerApiClient</code></td><td>production</td><td><code>src/client/designer-api-client.ts</code></td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Classes are standalone.</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer</th><th>Location</th></tr></thead><tbody><tr><td>Domain types from dag-core (<code>IDagDefinition</code>, <code>INodeManifest</code>, <code>TRunProgressEvent</code>)</td><td><code>DesignerApiClient</code>, hooks, components</td><td>Throughout <code>src/</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li>No dedicated test files found in this package currently.</li><li>The designer relies on integration testing through <code>dag-api</code> E2E tests and app-level UI tests.</li><li>Coverage priorities: API client request/response contract validation, SSE reconnection logic, hook state management, component rendering with manifests and definitions.</li><li>Run: <code>pnpm --filter @robota-sdk/dag-designer test</code></li></ul>',31)]))}const h=o(a,[["render",r]]);export{u as __pageData,h as default};
